#include <iostream>
#include <string>
#include <cstring>

class GameItem {
private:
    std::string name;
    int value;
    int* buffPtr;  // Pointer to demonstrate deep copy

public:
    // Constructor
    GameItem(std::string n, int v, int buff) : name(n), value(v) {
        buffPtr = new int(buff);
        std::cout << "GameItem created: " << name << std::endl;
    }

    // Copy constructor — deep copy
    GameItem(const GameItem& other) {
        name = other.name + " (copy)";
        value = other.value;
        buffPtr = new int(*other.buffPtr);  // Deep copy!
        std::cout << "Copy constructor called for " << name << std::endl;
    }

    // Copy assignment operator
    GameItem& operator=(const GameItem& other) {
        std::cout << "Assignment operator called for " << name << std::endl;

        // Self-assignment guard
        if (this == &other) {
            return *this;
        }

        // Copy data
        name = other.name + " (assigned)";
        value = other.value;

        // Deep copy
        delete buffPtr;  // Free old memory
        buffPtr = new int(*other.buffPtr);

        return *this;
    }

    // Destructor
    ~GameItem() {
        delete buffPtr;
        std::cout << "GameItem destroyed: " << name << std::endl;
    }

    void display() const {
        std::cout << "Item: " << name << ", Value: " << value 
                  << ", Buff: " << *buffPtr << std::endl;
    }

    void setBuff(int newBuff) {
        *buffPtr = newBuff;
    }
};

// Class without proper copy operations (demonstrates shallow copy issue)
class BrokenItem {
private:
    std::string name;
    int* healthPtr;

public:
    BrokenItem(std::string n, int h) : name(n) {
        healthPtr = new int(h);
        std::cout << "BrokenItem created: " << name << std::endl;
    }

    // No copy constructor — uses default (shallow copy!)
    // No assignment operator — uses default (shallow copy!)

    ~BrokenItem() {
        delete healthPtr;
        std::cout << "BrokenItem destroyed: " << name << std::endl;
    }

    void display() const {
        std::cout << name << " (HP: " << *healthPtr << ")" << std::endl;
    }

    void setHealth(int h) {
        *healthPtr = h;
    }
};

int main() {
    std::cout << "=== Copy Constructor & Assignment Operator ===" << std::endl;

    std::cout << "\n--- Creating Objects ---" << std::endl;
    GameItem sword("Iron Sword", 50, 10);
    sword.display();

    std::cout << "\n--- Copy Constructor ---" << std::endl;
    GameItem swordCopy = sword;  // Copy constructor called
    swordCopy.display();

    std::cout << "\n--- Assignment Operator ---" << std::endl;
    GameItem shield("Shield", 30, 15);
    shield.display();
    shield = sword;  // Assignment operator called
    shield.display();

    std::cout << "\n--- Modifying Original ---" << std::endl;
    sword.setBuff(20);
    std::cout << "Original: ";
    sword.display();
    std::cout << "Copy: ";
    swordCopy.display();
    std::cout << "Assigned: ";
    shield.display();

    std::cout << "\n=== Shallow Copy Issue ===" << std::endl;
    BrokenItem item1("Sword", 100);
    BrokenItem item2 = item1;  // Shallow copy! Both point to same memory

    item1.display();
    item2.display();

    std::cout << "Modifying item1..." << std::endl;
    item1.setHealth(200);
    item1.display();
    item2.display();  // Also changed! (shallow copy)

    std::cout << "\n--- End of main ---" << std::endl;
    // Destructors called — double delete for BrokenItem (undefined behavior!)

    return 0;
}

