#include <iostream>
#include <string>

class Weapon {
private:
    std::string name;
    int damage;
    int* buffPtr;

public:
    Weapon(std::string n, int d, int b) : name(n), damage(d) {
        buffPtr = new int(b);
        std::cout << "Weapon created: " << name << std::endl;
    }

    // Copy constructor
    Weapon(const Weapon& other) {
        name = other.name + " (copy)";
        damage = other.damage;
        buffPtr = new int(*other.buffPtr);
        std::cout << "Copying weapon... (" << name << ")" << std::endl;
    }

    // Assignment operator
    Weapon& operator=(const Weapon& other) {
        std::cout << "Assigning weapon..." << std::endl;
        if (this == &other) {
            return *this;
        }
        name = other.name + " (assigned)";
        damage = other.damage;
        delete buffPtr;
        buffPtr = new int(*other.buffPtr);
        return *this;
    }

    // Destructor
    ~Weapon() {
        delete buffPtr;
        std::cout << "Weapon destroyed: " << name << std::endl;
    }

    void display() const {
        std::cout << name << " (Damage: " << damage << ", Buff: " << *buffPtr << ")" << std::endl;
    }

    void setBuff(int newBuff) {
        *buffPtr = newBuff;
    }
};

int main() {
    Weapon weapon1("Sword", 15, 10);
    Weapon weapon2 = weapon1;
    Weapon weapon3("Axe", 20, 5);

    weapon3 = weapon1;

    weapon1.setBuff(25);

    std::cout << "\n=== Weapons ===" << std::endl;
    weapon1.display();
    weapon2.display();
    weapon3.display();

    return 0;
}
